+}
+
+/// Severity threshold used for CI validation failure gates.
+#[derive(Debug, Clone, Copy, ValueEnum, PartialEq, Eq)]
+enum FailOnSeverity {
+    None,
+    Hint,
+    Info,
+    Warning,
+    Error,
+}
+
+impl FailOnSeverity {
+    const fn rank(self) -> u8 {
+        match self {
+            Self::None => u8::MAX,
+            Self::Hint => 1,
+            Self::Info => 2,
+            Self::Warning => 3,
+            Self::Error => 4,
+        }
+    }
+}
